"""Tests for meridian_rig — the canonical bone table (spec ④ §2) and the
committed reference rig .glb it generates."""
import sys
from pathlib import Path

import pytest
import yaml

REPO = Path(__file__).resolve().parent.parent
sys.path.insert(0, str(REPO / "tools" / "blender" / "meridian_rig"))
import bones  # noqa: E402
import generate_rig  # noqa: E402

# The committed reference rig. Generated by generate_rig.py under Blender and
# stored via Git LFS; the structural tests below read it back with pygltflib so
# they run in CI without a Blender install.
RIG_GLB = REPO / "content/core/assets/art/char/sk_ardent_male_skeleton.glb"


def _is_lfs_pointer(path: Path) -> bool:
    """True when `path` is an unsmudged Git-LFS pointer rather than a real .glb.

    CI checks out without `lfs: true`, so the binary is a small text pointer
    there; the structural tests skip in that case and run locally (and on any
    LFS-smudged checkout) against the real geometry.
    """
    try:
        with open(path, "rb") as fh:
            return fh.read(64).startswith(b"version https://git-lfs")
    except FileNotFoundError:
        return False


skip_if_pointer = pytest.mark.skipif(
    _is_lfs_pointer(RIG_GLB),
    reason="rig .glb is an unsmudged LFS pointer (CI checkout without LFS smudge)",
)


def test_bone_count_is_63():
    assert len(bones.ALL_BONES) == 63
    assert len(bones.PROFILE_BONES) == 56
    assert len(bones.SOCKET_BONES) == 7

def test_hierarchy_is_wellformed_single_root():
    h = bones.hierarchy()
    roots = [n for n, p in h.items() if p is None]
    assert roots == ["Root"]
    names = set(h)
    assert all(p in names for p in h.values() if p is not None)

def test_socket_parents_match_spec():
    parents = {b.name: b.parent for b in bones.SOCKET_BONES}
    assert parents == {
        "socket_main_hand": "RightHand", "socket_off_hand": "LeftHand",
        "socket_shield": "LeftHand", "socket_back": "Chest",
        "socket_ranged": "Chest", "socket_hip_l": "Hips", "socket_hip_r": "Hips"}

def test_skeleton_defs_bones_matches_table():
    """Drift guard: schema/content/skeleton.defs.yaml bones == bones.py names."""
    defs = yaml.safe_load((REPO / "schema/content/skeleton.defs.yaml").read_text())
    assert defs["$defs"]["boneName"]["enum"] == bones.bone_names()

def test_unknown_profile_raises():
    with pytest.raises(ValueError, match="ardent_male"):
        bones.for_profile("dwarf_female")


# ---------------------------------------------------------------------------
# generate_rig — pure argument/path helpers (importable without bpy).
# ---------------------------------------------------------------------------
def test_argv_after_ddash_extracts_generator_args():
    argv = ["blender", "--background", "--python", "generate_rig.py",
            "--", "--profile", "ardent_male", "--out", "x.glb"]
    assert generate_rig.argv_after_ddash(argv) == [
        "--profile", "ardent_male", "--out", "x.glb"]


def test_argv_after_ddash_empty_when_no_separator():
    assert generate_rig.argv_after_ddash(["blender", "--background"]) == []


def test_parse_args_defaults_to_ardent_male():
    ns = generate_rig.parse_args([])
    assert ns.profile == "ardent_male"
    assert ns.out.endswith("sk_ardent_male_skeleton.glb")


def test_parse_args_reads_profile_and_out():
    ns = generate_rig.parse_args(["--profile", "ardent_male", "--out", "/tmp/r.glb"])
    assert ns.profile == "ardent_male"
    assert ns.out == "/tmp/r.glb"


def test_parse_args_rejects_unknown_profile():
    with pytest.raises(SystemExit):
        generate_rig.parse_args(["--profile", "dwarf_female"])


# ---------------------------------------------------------------------------
# Structural checks on the committed reference rig .glb (read back, no Blender).
# ---------------------------------------------------------------------------
def _load_rig_gltf():
    from pygltflib import GLTF2

    return GLTF2().load(str(RIG_GLB))


@pytest.mark.integration
@skip_if_pointer
def test_rig_glb_bone_names_match_table():
    g = _load_rig_gltf()
    node_names = {n.name for n in g.nodes}
    missing = set(bones.bone_names()) - node_names
    assert not missing, f"bones absent from exported .glb: {sorted(missing)}"


@pytest.mark.integration
@skip_if_pointer
def test_rig_glb_hierarchy_matches_table():
    g = _load_rig_gltf()
    child_to_parent: dict[str, str] = {}
    for n in g.nodes:
        for c in n.children or []:
            child_to_parent[g.nodes[c].name] = n.name
    for name, parent in bones.hierarchy().items():
        if parent is not None:
            assert child_to_parent.get(name) == parent, name


@pytest.mark.integration
@skip_if_pointer
def test_rig_glb_has_single_bone_root():
    """Exactly one table bone (Root) has no bone parent inside the armature."""
    g = _load_rig_gltf()
    child_to_parent: dict[str, str] = {}
    for n in g.nodes:
        for c in n.children or []:
            child_to_parent[g.nodes[c].name] = n.name
    table = set(bones.bone_names())
    unparented = {b for b in table if child_to_parent.get(b) not in table}
    assert unparented == {"Root"}, unparented
